import React,{useState,useEffect} from 'react'
import { useLocation } from 'react-router'
import requests from '../requests'
import YouTube from 'react-youtube'
import movieTrailer from "movie-trailer"
import axios from 'axios'
import SeasonsHolder from './SeasonsHolder'

function AllAbout({watchList,watchListLen,setWatchList,setWatchListLen}) {
    const location = useLocation()
    const {movie} = location.state
    const API_KEY = "20108f1c4ed38f7457c479849a9999cc"
    const [trailerUrl,setTrailerUrl] = useState("")
    const [showTrailer,setShowTrailer] = useState(false)
    const [inWatchList,setInWatchList] = useState(false)
    const [showWatch,setShowWatch] = useState(false)
    const [isTvShow,setIsTvShow] = useState(false)
    
    // check if  a movie or a tv show 
    useEffect(()=>{
        async function fetchIt(){
            const res = await axios.get(`https://api.themoviedb.org/3/tv/${id}?api_key=${API_KEY}`)
            if(res.success !== false){
                setIsTvShow(true);
            }
        }
        fetchIt()
    },[])

    // extract movie infos
    const backdrop_path = requests.image_api+movie.backdrop_path
    const poster_path = requests.image_api+movie.poster_path
    const {id,title,vote_average,original_name,overview,release_date} = movie
    // Youtube opts
    const opts = {
        width:"100%",
        height:"400px"
    }
    // get the movie trailer url on first load
    useEffect(()=>{
        if(!isTvShow) return false
        movieTrailer( title || movie.name || original_name || "" )
        .then(url=>{
            const urlParams = new URLSearchParams(new URL(url).search)
            setTrailerUrl(urlParams.get('v'))
        }).catch(err => console.log(err))
        watchList.map((m)=>{
            if(m.id === movie.id) return setInWatchList(true)
        })
    },[])

    const addToWatchListHandler = (e) =>{
        setWatchList([...watchList,movie])
        localStorage.setItem("watchlist",JSON.stringify(watchList))
        setWatchListLen(watchListLen++)
        e.target.style.display = "none"
    }

    return (
        <>
        <div className="all_about" style={{backgroundImage:`url(${backdrop_path})`,minHeight:window.innerHeight-75.2}}>
            <div className="cover"></div>
            <div className="inner_all_about">
                <div className="poster_holder">
                    <img src={poster_path} alt={id}/>
                </div>
                <div className="all_about_text_holder">
                    <h1>{title||original_name}</h1>
                    <h2>{release_date}</h2>
                    <h3>vote average {vote_average} ⭐</h3>
                    <p>{overview}</p>
                    <div className="all_about_buttons_row">
                        {!isTvShow && (<button id="Trailer" onClick={()=>setShowTrailer(true)}>trailer</button>)}
                        {inWatchList ?"":(<button id="watchList" onClick={addToWatchListHandler}>add to watch list</button>)}
                        {!isTvShow && (<button id="Trailer" onClick={()=>setShowWatch(true)}>Watch now</button>)}
                        
                        
                    </div>
                </div>
            </div>
            
            {showTrailer&&
            (<div className="trailer_popup" onClick={()=>setShowTrailer(false)}>
                <div className="youtube_vedio_holder">
                    <YouTube videoId={trailerUrl} opts={opts}/>
                </div> 
            </div>)
            }
            {showWatch &&
            (<div className="trailer_popup" onClick={()=>setShowWatch(false)}>
                {/* https://imdbapi.ml/embed/ */}
                <iframe title="film" src={`https://autoembed.xyz/movie/tmdb/${id}`} width="100%" height="100%" frameborder="0" allowFullScreen />
            </div>)}
            
        </div>
        {isTvShow && <SeasonsHolder id={id}/>}
        </>
    )
}

export default AllAbout
